const original = $node['Webhook Ingest'].json.body?.items || $node['Webhook Ingest'].json.items || [];

// For SSE-like responses, collect all delta.content text.
const rawBody = String($node['LLM Analyze (SSE)'].json.body || $node['LLM Analyze (SSE)'].json.data || '');
const chunks = rawBody.split(/\r?\n\r?\n/);
let merged = '';
for (const c of chunks) {
  const line = c.trim();
  if (!line.startsWith('data:')) continue;
  const payload = line.slice(5).trim();
  if (payload === '[DONE]') continue;
  try {
    const j = JSON.parse(payload);
    const part = j?.choices?.[0]?.delta?.content || '';
    if (part) merged += part;
  } catch {}
}

// Fallback: if response is plain JSON (not SSE), try direct parse.
let ai = { items: [] };
try {
  ai = JSON.parse(merged);
} catch {
  try {
    const direct = JSON.parse(rawBody);
    const content = direct?.choices?.[0]?.message?.content || '{}';
    ai = JSON.parse(content);
  } catch {
    ai = { items: [] };
  }
}

const aiMap = new Map((ai.items || []).map(x => [String(x.source_id || ''), x]));

const records = original.slice(0, 200).map((x) => {
  const sid = String(x.source_id || '');
  const isHn = sid.startsWith('hn:');
  const hnId = isHn ? sid.replace('hn:', '') : '';
  const m = aiMap.get(sid) || {};
  return {
    fields: {
      title: String(x.title || ''),
      url: String(x.url || ''),
      score: Number(x.score || 0),
      author: String(x.author || ''),
      published_at: String(x.published_at || ''),
      hn_comments: isHn ? `https://news.ycombinator.com/item?id=${hnId}` : '',
      source: String(x.source_name || x.source || ''),
      summary_cn: String(m.summary_cn || ''),
      tags: String(m.tags || ''),
      stance: String(m.stance || '')
    }
  };
});

return [{ json: { records, count: records.length, ai_raw_preview: merged.slice(0, 300) } }];
